-- Synthetic seed for agri-alert-via-port. All data fictional.
CREATE DATABASE IF NOT EXISTS agri;
CREATE DATABASE IF NOT EXISTS weather;
USE weather;
CREATE TABLE stations (station_id VARCHAR(16) PRIMARY KEY, place TEXT,
  latitude_deg DOUBLE, longitude_deg DOUBLE, elevation_m DOUBLE, responsible TEXT);
USE agri;
CREATE TABLE station_status (station_id VARCHAR(16) PRIMARY KEY,
  status ENUM('active','inactive','needs_maintenance'),
  created_at DATETIME, updated_at DATETIME);
CREATE TABLE station_status_log (id INT AUTO_INCREMENT PRIMARY KEY,
  station_id VARCHAR(16), old_status VARCHAR(32), new_status VARCHAR(32),
  note TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE farmer_contacts (id INT AUTO_INCREMENT PRIMARY KEY,
  reference TEXT, name TEXT, phone_number VARCHAR(9), active BOOLEAN,
  created_at DATETIME, updated_at DATETIME);
CREATE TABLE farmer_sectors (id INT AUTO_INCREMENT PRIMARY KEY,
  name TEXT, label VARCHAR(25), farmer_contact_id INT);
